exercises.solution_code:
#include <cstdint>
#include <iomanip>
#include <iostream>

int main() {
    int32_t i;
    double d;
    char c;
    bool b;

    int raw_bool;
    std::cin >> i >> d >> c >> raw_bool;
    b = (raw_bool != 0);

    std::cout << "int32: " << i << ", size=" << sizeof(i) << '\n';
    std::cout << "double: " << std::fixed << std::setprecision(1) << d << ", size=" << sizeof(d) << '\n';
    std::cout << "char: " << c << ", numeric=" << static_cast<int>(c) << '\n';
    std::cout << std::boolalpha << "bool: " << b << '\n';

    return 0;
}

