exercises.solution_code:
#include <iomanip>
#include <iostream>

int main() {
    int a, b;
    std::cin >> a >> b;

    int quotient  = a / b;
    int remainder = a % b;

    double da = a;
    double db = b;
    double true_result = da / db;

    std::cout << "integer division: " << quotient << '\n';
    std::cout << "remainder: " << remainder << '\n';
    std::cout << "true result: " << std::fixed << std::setprecision(2) << true_result << '\n';

    return 0;
}
